// NQxb_Gateway_v1__Normalize_Request
// Canonical normalization BEFORE Gatekeeper
// FIX: explicitly forward title + owner identity for artifact.save

function isNonEmptyObject(v) {
  return v && typeof v === "object" && !Array.isArray(v) && Object.keys(v).length > 0;
}

function pickSource() {
  if (isNonEmptyObject($json?.params)) return { src: "params", raw: $json.params };
  if (isNonEmptyObject($json?.query)) return { src: "query", raw: $json.query };
  if (isNonEmptyObject($json?.body?.body)) return { src: "body.body", raw: $json.body.body };
  if (isNonEmptyObject($json?.body)) return { src: "body", raw: $json.body };
  if (isNonEmptyObject($json)) return { src: "json", raw: $json };
  return { src: "empty", raw: {} };
}

const { src, raw } = pickSource();

return [
  {
    json: {
      // --- Canonical action ---
      gw_action: raw.gw_action ?? raw.action ?? null,

      // --- Workspace / identity ---
      gw_workspace_id: raw.gw_workspace_id ?? raw.workspace_id ?? null,
      workspace_id: raw.workspace_id ?? raw.gw_workspace_id ?? null,

      // --- Artifact identity ---
      artifact_type: raw.artifact_type ?? null,
      artifact_id: raw.artifact_id ?? null,

      // --- REQUIRED for INSERT ---
      title: raw.title ?? null,

      // --- Payload ---
      extension: raw.extension ?? raw.patch ?? {},
      tags: raw.tags ?? null,

      // --- Owner / auth passthrough ---
      auth_username:
        raw.auth_username ??
        raw.owner_username ??
        raw.created_by ??
        null,

      // --- Freeze intent ---
      req_gw_workspace_id: raw.gw_workspace_id ?? raw.workspace_id ?? null,
      req_artifact_type: raw.artifact_type ?? null,
      req_artifact_id: raw.artifact_id ?? null,
      req_title: raw.title ?? null,

      // --- Selector (artifact.list pagination) ---
      selector: raw.selector ?? {},

      // --- Promote fields ---
      transition: raw.transition ?? null,
      reason: raw.reason ?? null,

      _gw_debug: {
        normalized_by: "NQxb_Gateway_v1__Normalize_Request",
        source: src,
        received_keys: Object.keys(raw),
        has_title: !!raw.title,
        has_auth: !!(
          raw.auth_username ||
          raw.owner_username ||
          raw.created_by
        ),
      },
    },
  },
];

// NQxb_Gateway_v1__Gatekeeper_MVP_OwnerOnly
// Combined: envelope validation + allow-lists + MVP Mode owner-only enforcement (workspace lock)
//
// Output contract:
// - If blocked: { ok:false, error:{code,message,details}, _gw_route:"error", ... }
// - If allowed: passes through the *entire* canonical request + { ok:true, _gw_route:"ok" }

const OWNER_WORKSPACE_ID = "be0d3a48-c764-44f9-90c8-e846d9dbbd0a";

// ✅ Allowlist includes promote + update
const ACTION_ALLOWLIST = new Set([
  "artifact.query",
  "artifact.list",
  "artifact.save",
  "artifact.update",
  "artifact.promote",
  "artifact.delete",
  "artifact.restore",
  "artifact.list_deleted",
]);

// ✅ UPDATED: include instruction_pack
const TYPE_ALLOWLIST = new Set([
  "project",
  "journal",
  "restart",
  "snapshot",
  "instruction_pack",
]);

function asObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

function fail(code, message, details = {}) {
  return [
    {
      json: {
        ok: false,
        _gw_route: "error",
        error: { code, message, details },

        // Keep echoes for debugging
        gw_action: $json?.gw_action ?? null,
        gw_workspace_id: $json?.gw_workspace_id ?? null,
        artifact_type: $json?.artifact_type ?? null,
        artifact_id: $json?.artifact_id ?? null,
        selector: asObj($json?.selector),
        _gw_debug: $json?._gw_debug ?? undefined,

        // OPTIONAL: preserve original input for inspection (internal MVP)
        incoming: $json ?? {},
      },
    },
  ];
}

// ----- Read canonical fields produced by Normalize_Request -----
const gw_action = $json?.gw_action;
const gw_workspace_id = $json?.gw_workspace_id;
const artifact_type = $json?.artifact_type;
const artifact_id = $json?.artifact_id;
const selector = asObj($json?.selector);

// Extension + tags (tags-only updates are valid)
const extension = asObj($json?.extension);
const tags = asObj($json?.tags);

// ----- Basic required checks -----
if (!gw_action || typeof gw_action !== "string") {
  return fail("VALIDATION_ERROR", "Missing or invalid gw_action", {
    expected: "string",
    got: typeof gw_action,
  });
}

// ----- Allow-list checks -----
if (!ACTION_ALLOWLIST.has(gw_action)) {
  return fail("ACTION_NOT_ALLOWED", "gw_action not allowed", {
    gw_action,
    allowed: Array.from(ACTION_ALLOWLIST),
  });
}

/**
 * 🔑 CRITICAL FIX (BUG-017)
 *
 * We do NOT require gw_workspace_id at Gatekeeper time for artifact.update.
 * Update workflow performs authoritative workspace validation downstream.
 */
const requiresWorkspaceAtGate = gw_action !== "artifact.update";

if (requiresWorkspaceAtGate) {
  if (!gw_workspace_id || typeof gw_workspace_id !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid gw_workspace_id", {
      expected: "uuid string",
      got: typeof gw_workspace_id,
    });
  }

  // ----- MVP owner-only workspace lock -----
  if (gw_workspace_id !== OWNER_WORKSPACE_ID) {
    return fail("WORKSPACE_FORBIDDEN", "Workspace not permitted in MVP owner-only mode", {
      gw_workspace_id,
      allowed_workspace_id: OWNER_WORKSPACE_ID,
    });
  }
}

// ----- Action-specific validation -----
if (gw_action === "artifact.query") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_type for artifact.query", {
      expected: "string",
      got: typeof artifact_type,
    });
  }
  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }
  if (!artifact_id || typeof artifact_id !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_id for artifact.query", {
      expected: "uuid string",
      got: typeof artifact_id,
    });
  }
}

if (gw_action === "artifact.list") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_type for artifact.list", {
      expected: "string",
      got: typeof artifact_type,
    });
  }
  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }
  if (selector.limit !== undefined) {
    const n = Number(selector.limit);
    if (!Number.isFinite(n) || n < 1 || n > 100) {
      return fail("VALIDATION_ERROR", "selector.limit out of range (1-100)", {
        limit: selector.limit,
      });
    }
  }
}

// NOTE: For artifact.save we intentionally do NOT require artifact_type/artifact_id here.

if (gw_action === "artifact.update") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_type for artifact.update", {
      expected: "string",
      got: typeof artifact_type,
    });
  }
  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }
  if (!artifact_id || typeof artifact_id !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_id for artifact.update", {
      expected: "uuid string",
      got: typeof artifact_id,
    });
  }

  /**
   * 🔑 BUG-017 FIX:
   * Allow EITHER extension updates OR tags-only updates.
   */
  const hasExtension = Object.keys(extension).length > 0;
  const hasTags =
    Array.isArray(tags?.add) && tags.add.length > 0 ||
    Array.isArray(tags?.remove) && tags.remove.length > 0;

  if (!hasExtension && !hasTags) {
    return fail("VALIDATION_ERROR", "artifact.update requires extension or tags", {
      expected: "non-empty extension OR tags.add/tags.remove",
      got: { extension, tags },
    });
  }
}

if (gw_action === "artifact.promote") {
  if (!artifact_type || typeof artifact_type !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_type for artifact.promote", {
      expected: "string",
      got: typeof artifact_type,
    });
  }
  if (!TYPE_ALLOWLIST.has(artifact_type)) {
    return fail("ARTIFACT_TYPE_NOT_ALLOWED", "artifact_type not allowed", {
      artifact_type,
      allowed: Array.from(TYPE_ALLOWLIST),
    });
  }
  if (!artifact_id || typeof artifact_id !== "string") {
    return fail("VALIDATION_ERROR", "Missing or invalid artifact_id for artifact.promote", {
      expected: "uuid string",
      got: typeof artifact_id,
    });
  }

  const transition = $json?.transition ?? $json?.artifact_payload?.transition ?? null;

  if (!transition || typeof transition !== "string" || transition.trim().length === 0) {
    return fail("VALIDATION_ERROR", "Missing or invalid transition for artifact.promote", {
      expected: "non-empty string",
      got: transition ?? null,
    });
  }
}

// ----- PASS THROUGH + ADD ROUTING CONTRACT -----
return [
  {
    json: {
      ...($json ?? {}),

      ok: true,
      _gw_route: "ok",

      // enforce canonical fields
      gw_action,
      gw_workspace_id: gw_workspace_id ?? null,
      artifact_type: artifact_type ?? null,
      artifact_id: artifact_id ?? null,
      selector,

      ...(gw_action === "artifact.update" ? { extension, tags } : {}),

      _gw_debug: $json?._gw_debug ?? undefined,
    },
  },
];

